INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('8b344f7062bd7a8c', 'DC', '["federal","state","municipal","judicial"]', 'candidate_eligibility', 'Is the District of Columbia considered a state for election purposes?', '["Does D.C. operate like a regular U.S. state?","District of Columbia constitutional status","Is D.C. subject to federal control?"]', 'No. The District of Columbia is a federal district, not a state. Under Article I, Section 8, Clause 17 of the U.S. Constitution, Congress retains plenary (absolute) authority over D.C., though it was granted limited self-government under the D.C. Home Rule Act of 1973.', 'https://code.dccouncil.gov/us/dc/council/code/titles/1/chapters/2', 'D.C. Code § 1-201.01 (Home Rule Act)', '2026-05-13', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('9993292b5064c2c9', 'DC', '["state","municipal"]', 'candidate_eligibility', 'Does Congress have the authority to block laws passed by the D.C. Council?', '["Congressional review of D.C. laws","Can the federal government override the Mayor of D.C.?","30-day congressional review period"]', 'Yes. Under the Home Rule Act, all legislation passed by the D.C. Council and signed by the Mayor is subject to a 30-day congressional review period (60 days for criminal laws). Congress can override D.C. laws via a joint resolution, as it did in 2023 with the Revised Criminal Code Act.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-206.02', 'D.C. Code § 1-206.02', '2026-05-13', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('5db7680dba7265e4', 'DC', '["federal"]', 'election_dates', 'How many Electoral College votes does Washington, D.C. receive for presidential elections?', '["Does D.C. vote for President?","23rd Amendment D.C. electoral votes","Can D.C. residents vote for the president?"]', 'Under the 23rd Amendment to the U.S. Constitution (ratified in 1961), the District of Columbia is allocated 3 Electoral College votes for presidential elections, which is the minimum number granted to any state.', 'https://constitution.congress.gov/constitution/amendment-23/', 'U.S. Constitution, 23rd Amendment', '2026-05-13', 'static', 'statute_citation', 'Federal campaigns and Consultants', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('76c18963661e19c1', 'DC', '["federal"]', 'candidate_eligibility', 'Is Eleanor Holmes Norton running for re-election as D.C.''s U.S. House Delegate in 2026?', '["Is the D.C. Delegate seat open in 2026?","Who is replacing Eleanor Holmes Norton?","2026 D.C. non-voting delegate race"]', 'No. Delegate Eleanor Holmes Norton (D) announced in January 2026 that she will not seek re-election. This makes the non-voting U.S. House Delegate position an open seat for the first time since 1990.', 'https://dcboe.org/Elections/2026-Elections', 'D.C. Board of Elections – 2026 Elections', '2026-05-13', 'volatile', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('306166dae7ff8793', 'DC', '["federal"]', 'candidate_eligibility', 'What are the Shadow Senator and Shadow Representative positions in D.C.?', '["Does D.C. have real US Senators?","What does a shadow senator do?","D.C. statehood advocacy roles"]', 'D.C. voters elect two Shadow Senators and one Shadow Representative. These are unpaid advocacy roles created under D.C. Code § 1-129.01 to lobby Congress for statehood and federal recognition. They are not seated in Congress and hold no federal voting power.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-129.01', 'D.C. Code § 1-129.01', '2026-05-13', 'static', 'statute_citation', 'Federal candidates and consultants', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('2e23c33acf69afe8', 'DC', '["state"]', 'candidate_eligibility', 'Is Mayor Muriel Bowser running for re-election in 2026?', '["Is the D.C. Mayor''s seat open in 2026?","Can Muriel Bowser seek a fourth term?","D.C. 2026 mayoral race status"]', 'No. Mayor Muriel Bowser (D) announced in November 2025 that she will not seek a fourth consecutive term, making the 2026 D.C. mayoral race an open seat.', 'https://dcboe.org/Elections/2026-Elections', 'D.C. Board of Elections – 2026 Elections', '2026-05-13', 'volatile', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('77a6fa0284a9f5b9', 'DC', '["state","municipal"]', 'election_dates', 'What is the structure of the D.C. Council?', '["How many members are on the D.C. Council?","Are D.C. Council members elected at large?","D.C. legislative body composition"]', 'The D.C. Council is a 13-member legislative body consisting of a Chairman elected citywide, four At-Large members, and eight Ward members, all serving four-year terms.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.01', 'D.C. Code § 1-204.01', '2026-05-13', 'static', 'statute_citation', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('e5b85263f6c3b27c', 'DC', '["state","municipal"]', 'election_dates', 'Which D.C. Council seats are up for election in 2026?', '["Who is on the ballot in D.C. in 2026?","Is the D.C. Council Chairman up for reelection?","2026 D.C. ward elections"]', 'Half of the D.C. Council is on the 2026 ballot: the Chairman, two At-Large seats, and Wards 1, 3, 5, and 6. Under the Home Rule Charter, one of the two available At-Large seats must be reserved for a non-majority party or independent candidate.', 'https://dcboe.org/Elections/2026-Elections', 'D.C. Board of Elections – 2026 Elections', '2026-05-13', 'per_cycle', 'official_source_direct', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('1d019e52347c4f5d', 'DC', '["state"]', 'candidate_eligibility', 'Is Attorney General Brian Schwalb running for re-election in 2026?', '["Is the D.C. Attorney General''s seat open in 2026?","Who is the Attorney General of D.C.?","D.C. Attorney General election history"]', 'Yes. Attorney General Brian Schwalb (D), who was elected in 2022, is running for re-election. D.C. has only elected its Attorney General since 2014; the position was previously appointed.', 'https://dcboe.org/Elections/2026-Elections', 'D.C. Board of Elections – 2026 Elections', '2026-05-13', 'volatile', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('c8819ff067fd82ef', 'DC', '["state"]', 'election_dates', 'Is the Chief Financial Officer (CFO) an elected position in D.C.?', '["Does D.C. elect a Treasurer or Comptroller?","Who manages D.C. finances?","D.C. CFO appointment process"]', 'No. D.C. does not have an elected Treasurer or Comptroller. The Chief Financial Officer (CFO) is an independent position appointed by the Mayor and confirmed by the Council for a five-year term.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.24a', 'D.C. Code § 1-204.24a', '2026-05-13', 'static', 'statute_citation', 'Statewide candidates and consultants', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('03f8de0eb4ffb53e', 'DC', '["federal","state","municipal","judicial"]', 'election_dates', 'When is the 2026 D.C. Primary Election?', '["What date is the D.C. primary in 2026?","D.C. June primary date","When do polls open for the D.C. primary?"]', 'The D.C. Primary Election is scheduled for Tuesday, June 16, 2026. Under D.C. Code § 1-1001.05, the primary is held on the third Tuesday in June of non-presidential even-numbered years.', 'https://dcboe.org/Elections/2026-Elections', 'D.C. Board of Elections – 2026 Elections', '2026-05-13', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('edcf45c361b764be', 'DC', '["federal","state","municipal","judicial"]', 'election_dates', 'When is the 2026 D.C. General Election?', '["What date is the D.C. general election in 2026?","D.C. 2026 midterm election date","When is Election Day 2026 in Washington, D.C.?"]', 'The general election in the District of Columbia will be held concurrently with federal elections on Tuesday, November 3, 2026.', 'https://dcboe.org/Elections/2026-Elections', 'D.C. Board of Elections – 2026 Elections', '2026-05-13', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('9f8d8eed3c76df1a', 'DC', '["federal","state","municipal"]', 'runoff_rules', 'Will Ranked-Choice Voting (RCV) be used in the 2026 D.C. elections?', '["Did Initiative 83 pass in D.C.?","RCV implementation status D.C.","How does ranked-choice voting work in Washington D.C.?"]', 'The operational status is uncertain. Voters approved Initiative 83 in November 2024 to implement RCV, but the D.C. Council only partially funded it for 2025, and emergency legislation was introduced requiring a comprehensive needs assessment before rollout.', 'https://dcboe.org/Elections/2024-Elections', 'D.C. Board of Elections – Initiative 83', '2026-05-13', 'volatile', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('be51bb948bd95cf5', 'DC', '["federal","state","municipal"]', 'voter_interaction', 'Will D.C. have semi-open primaries for the 2026 election?', '["Can independents vote in the D.C. Democratic primary?","Initiative 83 open primary status","Are D.C. primaries closed?"]', 'Although Initiative 83 passed in 2024 to allow unaffiliated voters to participate in partisan primaries, the D.C. Council did not fund the open primaries component for 2025, leaving its implementation for 2026 uncertain. Historically, D.C. primaries have been strictly closed.', 'https://dcboe.org/Elections/2024-Elections', 'D.C. Board of Elections – Initiative 83', '2026-05-13', 'volatile', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('509d242c6a2c4307', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'Do all D.C. voters automatically receive a mail-in ballot?', '["Universal mail voting D.C.","Do I have to request an absentee ballot in Washington D.C.?","D.C. vote-by-mail default rules"]', 'Yes. Under the Election Reform Amendment Act (codified at D.C. Code § 1-1001.05), D.C. uses a universal mail-in voting system where every active registered voter is automatically mailed a ballot unless they explicitly opt out.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.05', 'D.C. Code § 1-1001.05', '2026-05-13', 'static', 'statute_citation', 'All voters', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('53d41b44ef2a0a2a', 'DC', '["federal","state","municipal","judicial"]', 'election_dates', 'What is the deadline for a mail-in ballot to be received and counted in D.C.?', '["When is my absentee ballot due in D.C.?","D.C. mail ballot postmark rule","10-day receipt deadline for ballots D.C."]', 'Mail-in ballots must be postmarked on or before Election Day and received by the D.C. Board of Elections no later than the 10th day after the election to be counted, providing a distinctively long postmark grace period.', 'https://dcboe.org/Voters/Absentee-Voting', 'D.C. Board of Elections – Absentee Voting', '2026-05-13', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('0ba43b5f0c0bf1de', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'Does D.C. allow same-day voter registration at polling places?', '["Can I register to vote at the polls in Washington D.C.?","Same-day registration rules D.C.","Election day registration D.C."]', 'Yes. D.C., which was the first jurisdiction in the U.S. to implement same-day voter registration in 1981, allows eligible citizens to register and vote at early voting centers and Election Day polling places using valid proof of residence.', 'https://dcboe.org/Voters/Register-To-Vote/Same-Day-Voter-Registration', 'D.C. Board of Elections – Same-Day Voter Registration', '2026-05-13', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('f6ebd047d09ed7d5', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'Is a photo ID required to vote at the polls in D.C.?', '["D.C. voter ID laws","Poll ID requirements Washington D.C.","Do I need my driver''s license to vote in D.C.?"]', 'No. D.C. currently does not require voters to show a photo ID at the polls, relying instead on signature matching. Unlike Nevada, D.C. does not have a pending constitutional-style charter amendment (like Question 7) requiring photo ID.', 'https://dcboe.org/Voters/Election-Day-Voting/ID-Requirements', 'D.C. Board of Elections – ID Requirements', '2026-05-13', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('c7b2d5071f58a114', 'DC', '["federal","state","municipal","judicial"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in D.C.?', '["Felon voting rights D.C.","Voting post-incarceration rules Washington D.C.","Can prisoners vote in D.C.?"]', 'Yes. D.C. is the first and only jurisdiction in the U.S. to pass legislation (the Restore the Vote Amendment Act of 2020) that allows residents incarcerated for felony convictions to retain their voting rights and cast absentee ballots while in prison.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.06', 'D.C. Code § 1-1001.06', '2026-05-13', 'static', 'statute_citation', 'All eligible citizens', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('ca12ebede107b15b', 'DC', '["state","municipal"]', 'finance_ethics', 'Who enforces campaign finance rules in D.C.?', '["Jurisdiction of the OCF in D.C.","Where do I file campaign finance reports in Washington D.C.?","D.C. Office of Campaign Finance role"]', 'Campaign finance is administered by the Office of Campaign Finance (OCF), which operates as an independent agency within the D.C. Board of Elections (BOE).', 'https://ocf.dc.gov/', 'D.C. Office of Campaign Finance', '2026-05-13', 'static', 'official_source_direct', 'Candidates and Campaign Treasurers', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('4c4fc1e04f4cc3c8', 'DC', '["state","municipal"]', 'finance_ethics', 'What is the Fair Elections Program (FEP) in D.C.?', '["D.C. public financing system","How does the FEP matching system work?","Voluntary public campaign funds D.C."]', 'The FEP is a voluntary public financing program. Participating candidates agree to accept lower contribution limits and donations exclusively from individuals (no business or PAC money). In return, they receive a base grant and 5-to-1 matching funds for small-dollar contributions from D.C. residents.', 'https://ocf.dc.gov/page/fair-elections-program', 'D.C. Office of Campaign Finance – Fair Elections Program', '2026-05-13', 'static', 'official_source_direct', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('7a25554c7a6295ad', 'DC', '["state","municipal"]', 'finance_ethics', 'What are the standard individual contribution limits for D.C. local candidates?', '["How much can an individual give to a Mayor candidate in D.C.?","D.C. contribution limits 2026","State Board of Education maximum donation D.C."]', 'Under D.C. Code § 1-1163.33, the traditional contribution limits are $2,000 for Mayor, $1,500 for Attorney General and Council Chairman, $1,000 for At-Large Council, $500 for Ward Council and State Board of Education (SBOE) At-Large, $200 for SBOE Ward, and $25 for Advisory Neighborhood Commission.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1163.33', 'D.C. Code § 1-1163.33', '2026-05-13', 'per_cycle', 'statute_citation', 'Candidates and donors', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('226c6b03e3b3439b', 'DC', '["judicial"]', 'election_dates', 'How are judges selected for the D.C. Superior Court and Court of Appeals?', '["Are judges elected in Washington D.C.?","D.C. judicial selection process","Who appoints judges in the District of Columbia?"]', 'D.C. voters do not elect or retain judges. Under the Home Rule Act, all judges for the D.C. Superior Court and D.C. Court of Appeals are appointed by the President of the United States, with advice and consent of the U.S. Senate, to serve 15-year terms.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.33', 'D.C. Code § 1-204.33', '2026-05-13', 'static', 'statute_citation', 'Judicial candidates and nominees', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('0d616608971fadba', 'DC', '["state","municipal"]', 'recall_rules', 'Can voters recall the Mayor or Council members in D.C.?', '["D.C. recall mechanism","How to recall a politician in Washington D.C.","Does D.C. have a recall by petition?"]', 'Yes. Under D.C. Code § 1-204.111, voters can recall the Mayor, Attorney General, or Council members. A recall petition requires signatures from 10% of the registered voters in the jurisdiction, and the official must have been in office for at least 6 months.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.111', 'D.C. Code § 1-204.111', '2026-05-13', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('d7f25456c6248709', 'DC', '["state","municipal"]', 'ballot_access', 'Does D.C. have a state constitution?', '["Washington D.C. statehood constitution","D.C. constitutional status","Has D.C. adopted a constitution?"]', 'In 2016, D.C. voters overwhelmingly approved an advisory referendum for statehood, adopting a draft constitution for the proposed ''State of Washington, D.C.'' However, Congress has not passed legislation (such as H.R. 51) to admit D.C. as a state, so it remains a federal district governed by the Home Rule Charter.', 'https://statehood.dc.gov/', 'D.C. Statehood Initiatives', '2026-05-13', 'static', 'official_source_direct', 'All Campaigns and Strategists', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('691e4cca501240e1', 'DC', '["state","municipal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for Mayor of D.C.?', '["How old do you have to be to be D.C. Mayor?","Mayoral candidate residency rules D.C.","Qualifications for Mayor of Washington D.C."]', 'Under D.C. Code § 1-204.21, a candidate for Mayor must be at least 30 years old, a registered voter in the District, and must have been a resident and domiciled in D.C. for at least three years immediately preceding the election.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.21', 'D.C. Code § 1-204.21', '2026-05-13', 'static', 'statute_citation', 'Gubernatorial/Mayoral candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('3156f3b075d346b6', 'DC', '["state","municipal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for D.C. Council Chairman?', '["How old to run for Council Chairman D.C.?","District residency for Council Chairman","Qualifications for Chairman of the D.C. Council"]', 'Under D.C. Code § 1-204.01, a candidate for Chairman of the Council must be at least 30 years old, a registered voter, and a resident of the District of Columbia for at least one year immediately preceding the general election.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.01', 'D.C. Code § 1-204.01', '2026-05-13', 'static', 'statute_citation', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('3d3f57c1b7f8341b', 'DC', '["state","municipal"]', 'candidate_eligibility', 'What are the qualifications to run for an At-Large seat on the D.C. Council?', '["How old to run for At-Large Council D.C.?","Residency rules for At-Large Councilmember","D.C. At-Large candidate requirements"]', 'Under D.C. Code § 1-204.01, a candidate for an At-Large Council seat must be at least 25 years old, a registered voter, and a resident of D.C. for at least one year prior to the election.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.01', 'D.C. Code § 1-204.01', '2026-05-13', 'static', 'statute_citation', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('f7f757226b9087f5', 'DC', '["municipal"]', 'candidate_eligibility', 'What are the qualifications to run for a Ward seat on the D.C. Council?', '["How old to run for Ward Council D.C.?","Do I have to live in the ward to run for D.C. Council?","Ward residency rules D.C."]', 'Under D.C. Code § 1-204.01, a candidate for a Ward Council seat must be at least 25 years old, a registered voter, a resident of D.C. for at least one year, and specifically a resident of the ward from which they are nominated at the time of filing.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.01', 'D.C. Code § 1-204.01', '2026-05-13', 'static', 'statute_citation', 'Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('014a0ad294f34179', 'DC', '["state"]', 'candidate_eligibility', 'What are the specific qualifications to run for Attorney General in D.C.?', '["Do I have to be a lawyer to be AG in D.C.?","Attorney General residency rules Washington D.C.","D.C. Bar requirement for Attorney General"]', 'Under D.C. Code § 1-301.81, a candidate for Attorney General must be a registered voter and resident of D.C., and importantly, must have been actively engaged in the practice of law in the District of Columbia for at least the 5 years immediately preceding the election.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-301.81', 'D.C. Code § 1-301.81', '2026-05-13', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('6f5af4ef4844e369', 'DC', '["state","municipal"]', 'candidate_eligibility', 'What are the qualifications to run for the D.C. State Board of Education (SBOE)?', '["How old do you have to be to run for D.C. SBOE?","State Board of Education eligibility D.C.","Do I have to live in the ward to run for SBOE?"]', 'Under D.C. Code § 1-1001.07, a candidate for the State Board of Education must be at least 18 years old, a registered voter, and a resident of the District (and the specific ward, if running for a ward seat) for at least one year prior to the election.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.07', 'D.C. Code § 1-1001.07', '2026-05-13', 'static', 'statute_citation', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('2d8d4894016dea83', 'DC', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for D.C.''s U.S. House Delegate?', '["How old to run for Non-Voting Delegate D.C.?","Congressional age limit D.C.","U.S. House qualifications District of Columbia"]', 'The Non-Voting Delegate must meet the qualifications of a U.S. House Representative under the U.S. Constitution (at least 25 years old, a U.S. citizen for seven years) and must be an inhabitant and qualified elector of the District of Columbia.', 'https://dcboe.org/Elections/Candidates/Running-for-Office', 'D.C. Board of Elections – Candidate Qualifications', '2026-05-13', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('f10906189a16c417', 'DC', '["federal"]', 'candidate_eligibility', 'What is the term length and eligibility requirement for a D.C. Shadow Senator?', '["How long do D.C. Shadow Senators serve?","Are Shadow Senators elected for 4 or 6 years?","Shadow Senator qualifications D.C."]', 'Shadow Senators must meet the qualifications of a U.S. Senator (at least 30 years old, a U.S. citizen for nine years, and an inhabitant of D.C.). Distinctively, while sometimes miscited as having 4-year terms, D.C. Code § 1-129.05 explicitly establishes that Shadow Senators serve 6-year terms, mirroring actual U.S. Senators.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-129.05', 'D.C. Code § 1-129.05', '2026-05-13', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('827b9485d5b8d3d3', 'DC', '["municipal"]', 'candidate_eligibility', 'What are the qualifications to serve as an Advisory Neighborhood Commissioner (ANC) in D.C.?', '["How old to run for ANC in Washington D.C.?","ANC residency rules D.C.","Single Member District eligibility"]', 'To run for one of the 296 unpaid ANC seats, a candidate must be at least 18 years old, a registered voter, and a continuous resident of the specific Single Member District (SMD) they seek to represent for at least 60 days before the election.', 'https://anc.dc.gov/page/about-ancs', 'D.C. Advisory Neighborhood Commissions', '2026-05-13', 'static', 'official_source_direct', 'Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('57dfdf9fced513ab', 'DC', '["state","municipal"]', 'election_dates', 'Who succeeds the Mayor of D.C. in the event of a vacancy?', '["What happens if the D.C. Mayor resigns?","Acting Mayor D.C. succession","Mayoral vacancy fill D.C."]', 'Under the Home Rule Act, if the Mayor''s office becomes vacant, the Chairman of the D.C. Council automatically becomes the Acting Mayor. A special election must then be held within 114 days to fill the remainder of the unexpired term.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.21', 'D.C. Code § 1-204.21(c)(2)', '2026-05-13', 'static', 'statute_citation', 'Statewide officials and campaigns', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('c2a63f3c912d1721', 'DC', '["state","municipal"]', 'election_dates', 'How are mid-term vacancies filled on the D.C. Council?', '["D.C. Council special elections","Filling a Council seat in Washington D.C.","Interim appointment for D.C. Council"]', 'A vacancy on the D.C. Council triggers a special election, which must be held within 114 days. During the interim period, the respective political party''s central committee may appoint a temporary replacement for partisan seats, while the Council itself appoints interim replacements for independent at-large seats.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.01', 'D.C. Code § 1-204.01(b)(3)', '2026-05-13', 'static', 'statute_citation', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('b293f0213628e23d', 'DC', '["judicial"]', 'election_dates', 'How are judicial vacancies filled in D.C., and is there a mandatory retirement age?', '["Who appoints judges in Washington D.C.?","Judicial Nominating Commission D.C.","D.C. judicial mandatory retirement 74"]', 'Judicial vacancies in D.C. are filled by the President of the United States with U.S. Senate confirmation, based on binding recommendations from the Judicial Nomination Commission. D.C. judges face a strict mandatory retirement age of 74, after which they may apply for senior judge status.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.31', 'D.C. Code § 1-204.31 (Home Rule Act § 431)', '2026-05-13', 'static', 'statute_citation', 'Judicial candidates and nominees', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('ede9757840ae6261', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'What is the pre-election voter registration deadline in Washington D.C.?', '["When is the last day to register online to vote in D.C.?","21-day registration rule D.C.","Voter registration deadline prior to same-day D.C."]', 'The deadline to pre-register to vote online or by mail in D.C. is 21 days before the election. However, D.C. offers Same-Day Registration, allowing voters who miss this deadline to register in person during early voting or on Election Day.', 'https://dcboe.org/Voters/Register-To-Vote/Register-to-Vote', 'D.C. Board of Elections – Voter Registration', '2026-05-13', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('45917e6ba981485d', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'How long is the early voting window in Washington D.C.?', '["When does early voting start in D.C.?","14-day early voting rule D.C.","D.C. in-person early voting duration"]', 'Under D.C. Code § 1-1001.05, D.C. provides a mandatory early voting period of at least 14 days prior to the election. The Board of Elections establishes early voting centers in every ward across the city.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.05', 'D.C. Code § 1-1001.05', '2026-05-13', 'static', 'statute_citation', 'All voters and GOTV operations', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('3c7df9a4e5578412', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'Can D.C. voters opt out of receiving a universal mail-in ballot?', '["Universal mail voting opt-out D.C.","How to stop getting mail ballots in D.C.","D.C. vote-by-mail preferences"]', 'Yes. While D.C. operates a universal mail-in voting system where every active registered voter is automatically mailed a ballot, D.C. Code § 1-1001.05 allows voters to formally submit a request to opt out of the automatic mailing if they prefer to vote exclusively in person.', 'https://dcboe.org/Voters/Absentee-Voting/Mail-In-Voting', 'D.C. Board of Elections – Mail-In Voting', '2026-05-13', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('fa964b6c7e996f6f', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'Can 16-year-olds pre-register to vote in D.C.?', '["Teenager voter registration D.C.","Pre-registration age Washington D.C.","When can high school students register to vote in D.C.?"]', 'Yes. Under D.C. Code § 1-1001.07, a resident who is 16 or 17 years old may pre-register to vote. Their registration is held in a ''pending'' status and becomes fully active automatically when they reach the eligible voting age.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.07', 'D.C. Code § 1-1001.07', '2026-05-13', 'static', 'statute_citation', 'Unregistered voters and GOTV operations', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('b5c5344515d3edf6', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'Does D.C. law require employers to grant paid time off to vote?', '["Do I get paid time off to vote in D.C.?","Employee voting leave D.C.","2 hours off to vote rule Washington D.C."]', 'Yes. Under D.C. Code § 1-612.07, employers must grant employees up to two hours of paid leave to vote in a D.C. election (or an election in the jurisdiction where they are eligible to vote), provided the employee requests the leave in advance.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-612.07', 'D.C. Code § 1-612.07', '2026-05-13', 'static', 'statute_citation', 'Voters and Employers', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('713463e02569cf43', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'What is the electioneering buffer zone at D.C. polling places?', '["How close to the door can I campaign in D.C.?","50-foot rule D.C. voting","Campaign signs at polling places Washington D.C."]', 'D.C. enforces a 50-foot electioneering buffer zone measured from the entrance and exit of a polling place. Under D.C. Code § 1-1001.10, no campaign materials, sign distribution, or voter solicitation is permitted within this boundary.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.10', 'D.C. Code § 1-1001.10', '2026-05-13', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('6c52d21071e17fa6', 'DC', '["state","municipal"]', 'voter_interaction', 'Can non-citizens vote in Washington D.C. elections?', '["Non-citizen voting rights D.C.","Can immigrants vote in local D.C. races?","D.C. Law 24-242 local elections"]', 'Yes, but for local races only. Under the Local Resident Voting Rights Amendment Act of 2022 (D.C. Law 24-242), D.C. allows non-citizen residents of the District to register and vote in local municipal elections, such as those for Mayor, Council, Attorney General, and ANCs.', 'https://code.dccouncil.gov/us/dc/council/laws/24-242', 'D.C. Law 24-242', '2026-05-13', 'static', 'statute_citation', 'All voters and Get-Out-The-Vote operations', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('c5fad67a44b106ba', 'DC', '["state"]', 'ballot_access', 'How many petition signatures are required for a mayoral candidate in the D.C. primary?', '["D.C. Mayor signature requirement","How many signatures to run for Mayor in D.C.?","Primary petition threshold Washington D.C."]', 'Under D.C. Code § 1-1001.08, a partisan candidate for Mayor (as well as Council Chairman and Attorney General) must collect valid signatures from at least 2,000 registered voters of their specific political party to qualify for the primary election ballot.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.08', 'D.C. Code § 1-1001.08', '2026-05-13', 'static', 'statute_citation', 'Mayoral candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('9fc4efd38138b207', 'DC', '["municipal"]', 'ballot_access', 'What is the signature requirement for a Ward Council candidate in the D.C. primary?', '["D.C. Ward Council signature limit","How many signatures to run for D.C. Council in a ward?","Ward petition threshold D.C."]', 'To qualify for the primary ballot, a candidate for a Ward seat on the D.C. Council must collect valid signatures from at least 500 registered voters who reside in that specific ward and are affiliated with the candidate''s political party.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.08', 'D.C. Code § 1-1001.08', '2026-05-13', 'static', 'statute_citation', 'Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('646a69b0702f371e', 'DC', '["state","municipal"]', 'finance_ethics', 'What is the itemized disclosure threshold for campaign expenditures in D.C.?', '["D.C. expenditure reporting limit","When do I have to list a vendor for my campaign in D.C.?","D.C. $10 expense rule"]', 'D.C. has a distinctively low expenditure disclosure threshold. Campaigns must itemize and report any campaign expenditure of $10 or more, detailing the payee and the precise purpose of the expense.', 'https://ocf.dc.gov/page/campaign-finance-guide', 'D.C. Office of Campaign Finance', '2026-05-13', 'static', 'official_source_direct', 'Campaign Treasurers', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('c7baf1a89c4bbd94', 'DC', '["state","municipal"]', 'finance_ethics', 'What is the base payment amount for Fair Elections Program candidates other than Mayor?', '["FEP base grant for D.C. Council","How much public money does an Attorney General candidate get?","State Board of Education FEP base amount"]', 'Certified Fair Elections Program (FEP) candidates receive an initial base grant depending on the office: $40,000 for Attorney General, Council Chairman, At-Large Council, and Ward Council. State Board of Education (SBOE) candidates receive $10,000.', 'https://dcfairelections.org/faq/', 'D.C. Fair Elections Program FAQ', '2026-05-13', 'static', 'official_source_direct', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('ce2a4a1298a0aac0', 'DC', '["state","municipal"]', 'finance_ethics', 'How does a candidate qualify for the Fair Elections Program in D.C.?', '["FEP certification requirements D.C.","How many donors to get public funds for D.C. Council?","Attorney General qualifying threshold D.C. Fair Elections"]', 'Candidates must collect small-dollar contributions from unique D.C. residents. Thresholds are: Attorney General (500 donors/$20k), Council Chairman (300/$15k), At-Large Council (250/$12k), Ward Council and SBOE At-Large (150/$5k), and SBOE Ward (50/$1k).', 'https://dcfairelections.org/faq/', 'D.C. Fair Elections Program FAQ', '2026-05-13', 'static', 'official_source_direct', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('938bffad6e8b053c', 'DC', '["state","municipal"]', 'finance_ethics', 'What is the matching ratio for the D.C. Fair Elections Program?', '["FEP match rate Washington D.C.","How are small dollar donations matched in D.C.?","D.C. public financing formula"]', 'D.C. provides a 5-to-1 matching ratio for qualifying small-dollar contributions from District residents. For example, a $50 contribution from a D.C. resident yields $250 in matching public funds, generating $300 total for the campaign.', 'https://dcfairelections.org/faq/', 'D.C. Fair Elections Program FAQ', '2026-05-13', 'static', 'official_source_direct', 'Participating Candidates and Donors', 'batch_2026-05-13T20-35-58_dc_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('f3aa13c74e7c7a48', 'DC', '["state","municipal"]', 'finance_ethics', 'What is the limit on cash contributions for D.C. campaigns?', '["Can I donate cash in Washington D.C.?","Cash contribution cap D.C. Code","D.C. $25 cash limit"]', 'Under D.C. Code § 1-1163.33(c), no person shall make a cash contribution to any political committee or candidate in excess of $25. Any contribution over $25 must be made by check, credit card, or other verifiable electronic means.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1163.33', 'D.C. Code § 1-1163.33(c)', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers and Donors', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('c5ea4fa918e10d2f', 'DC', '["state","municipal"]', 'finance_ethics', 'What is the maximum aggregate contribution an individual can make to all D.C. candidates combined per election?', '["Total aggregate contribution limit D.C.","How much total can I donate to local D.C. races?","D.C. Code 1-1163.33(b) individual cap"]', 'Under D.C. Code § 1-1163.33(b), no individual may contribute more than an aggregate of $8,500 in any one election to all candidates for Mayor, Chairman, Council, and State Board of Education combined.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1163.33', 'D.C. Code § 1-1163.33(b)', '2026-05-13', 'static', 'statute_citation', 'Donors', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('a46ea864fa2e51b7', 'DC', '["state","municipal"]', 'finance_ethics', 'How are corporate contributions aggregated in D.C. campaign finance?', '["D.C. business contributor affiliation limits","Do LLCs and parent companies share a contribution limit?","D.C. Code corporate aggregation rule"]', 'Under D.C. Code § 1-1163.33, all contributions made by a corporation, its subsidiaries, affiliated partnerships, LLCs, and other connected business entities sharing majority ownership or control are aggregated and treated as being made by a single person for the purpose of contribution limits.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1163.33', 'D.C. Code § 1-1163.33', '2026-05-13', 'static', 'statute_citation', 'Corporations and Campaign Treasurers', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('047a3dc86e4b5ca3', 'DC', '["federal","state","municipal"]', 'finance_ethics', 'What are the disclaimer requirements for political advertising in Washington D.C.?', '["D.C. political ad disclaimer rules","Who paid for this ad disclaimer D.C.","Print and broadcast ad attributions D.C."]', 'Under D.C. Code § 1-1163.15, all political advertisements, campaign literature, and electronic communications must include a clear ''Paid for by'' attribution stating the name and address of the committee or person funding the ad. D.C. law applies to print, digital, and broadcast, subject to concurrent federal FCC rules.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1163.15', 'D.C. Code § 1-1163.15', '2026-05-13', 'static', 'statute_citation', 'All Campaigns and Strategists', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('3a2eda8586e9d73a', 'DC', '["federal","state","municipal"]', 'filing_requirements', 'What is the candidate filing fee in Washington D.C.?', '["How much does it cost to run for office in D.C.?","D.C. Board of Elections filing fees 2026","Do I have to pay to get on the ballot in D.C.?"]', 'There is no filing fee to run for public office in the District of Columbia ($0). Ballot access is achieved exclusively by obtaining and filing the required number of valid nominating petition signatures.', 'https://dcboe.org/Elections/Candidates/Running-for-Office', 'D.C. Board of Elections – Running for Office', '2026-05-13', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('1565c601a70e3f4a', 'DC', '["state","municipal"]', 'ballot_access', 'What is the signature requirement for an At-Large Council candidate in the D.C. primary?', '["D.C. At-Large Council signature limit","How many signatures to run for D.C. Council At-Large?","1,500 signatures from 5 wards requirement D.C."]', 'To qualify for the primary ballot, a candidate for an At-Large Council seat (as well as Mayor, AG, and Chairman) must collect 2,000 valid signatures or 1% of registered voters in their party, whichever is less. The assertion that 1,500 signatures from 5 wards are required is incorrect under D.C. Code § 1-1001.08.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.08', 'D.C. Code § 1-1001.08(j)(1)', '2026-05-13', 'static', 'statute_citation', 'State and Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('b8deab20e8cc6097', 'DC', '["federal","state","municipal"]', 'ballot_access', 'What is the signature requirement for an independent candidate seeking citywide office in D.C.?', '["D.C. independent candidate deadline and signatures","Nomination by petition general election D.C.","How to run as an independent for Mayor in D.C."]', 'Independent or minor-party candidates seeking citywide offices (Mayor, AG, Chairman, At-Large Council, or federal Delegate/Shadow roles) directly for the general election must collect valid signatures from 3,000 registered voters, or 1.5% of all registered voters, whichever is less.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.08', 'D.C. Code § 1-1001.08(j)(1)', '2026-05-13', 'static', 'statute_citation', 'Independent candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('d83bb85c74c6cefc', 'DC', '["federal","state","municipal"]', 'ballot_access', 'Which minor political parties are officially recognized for ballot access in D.C.?', '["D.C. Statehood Green Party status","Minor parties in Washington D.C.","What parties are on the D.C. ballot?"]', 'In addition to the Democratic and Republican parties, D.C. officially recognizes the D.C. Statehood Green Party (a merged entity of the Statehood Party and Green Party) and the Libertarian Party. Candidates from these parties gain primary ballot access through lower signature thresholds than non-affiliated independents.', 'https://dcboe.org/Voters/Register-To-Vote/Political-Parties', 'D.C. Board of Elections – Political Parties', '2026-05-13', 'static', 'official_source_direct', 'Minor party candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('619b0a3b57d2ddeb', 'DC', '["state","municipal"]', 'ballot_access', 'How many signatures are required to qualify a ballot initiative in D.C.?', '["D.C. ballot initiative requirements","How to put a measure on the ballot in Washington D.C.","5% ward signature rule D.C."]', 'Under D.C. Code § 1-1001.16, qualifying an initiative or referendum requires valid signatures from at least 5% of all registered voters citywide, and this must include at least 5% of the registered voters in five or more of the eight individual wards.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.16', 'D.C. Code § 1-1001.16', '2026-05-13', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('b19ea46e26ea9baf', 'DC', '["state","municipal"]', 'ballot_access', 'Are there subject matter restrictions on ballot initiatives in D.C.?', '["What can a D.C. ballot initiative cover?","Can an initiative appropriate funds in D.C.?","Federal restrictions on D.C. initiatives"]', 'Yes. The Home Rule Act strictly prohibits D.C. ballot initiatives from authorizing or requiring the appropriation of funds. The D.C. Board of Elections will reject any proposed initiative measure that disrupts the District''s congressionally approved budget.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-204.103', 'D.C. Code § 1-204.103 (Home Rule Act § 4103)', '2026-05-13', 'static', 'statute_citation', 'Ballot measure committees and Strategists', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('18f3b928731ed479', 'DC', '["state","municipal"]', 'ballot_access', 'Are voter-approved ballot initiatives in D.C. subject to Congressional review?', '["Can Congress block a D.C. initiative?","30-day review for D.C. ballot measures","What happens after an initiative passes in D.C.?"]', 'Yes. Even if overwhelmingly approved by D.C. voters, an initiative becomes an act of the D.C. Council and remains subject to the Home Rule Act''s mandatory 30-day Congressional review period, during which Congress can override it.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-206.02', 'D.C. Code § 1-206.02', '2026-05-13', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('6138c81ee82cdc4e', 'DC', '["state","municipal"]', 'ballot_access', 'What is the referendum process in D.C.?', '["Can D.C. voters repeal a Council law?","D.C. Code § 1-1001.16 referendum","Voter veto of D.C. legislation"]', 'The referendum process allows voters to suspend and potentially repeal acts recently passed by the D.C. Council. Proponents must submit valid signatures equal to 5% of registered voters (with 5% in at least five wards) before the legislation goes into effect.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-1001.16', 'D.C. Code § 1-1001.16', '2026-05-13', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('27f38c769bfb6297', 'DC', '["municipal"]', 'redistricting', 'How are the ward boundaries drawn in D.C.?', '["D.C. ward redistricting 2022","Who draws the D.C. ward map?","Decennial redistricting Washington D.C."]', 'Following each decennial census, the D.C. Council passes legislation to redraw the boundaries of the District''s eight wards to ensure population equality. The most recent redistricting was completed in early 2022 for use through the 2030 census cycle.', 'https://dccouncil.gov/redistricting/', 'D.C. Council – Redistricting', '2026-05-13', 'static', 'official_source_direct', 'Municipal candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('6984c6a683c1f804', 'DC', '["judicial"]', 'election_dates', 'What is the structure of the D.C. Court of Appeals?', '["Highest court in Washington D.C.","How many judges on the D.C. Court of Appeals?","D.C. appellate court composition"]', 'The D.C. Court of Appeals is the highest local court for the District of Columbia. It consists of nine judges (one Chief Judge and eight Associate Judges) who are appointed by the President to 15-year terms.', 'https://www.dccourts.gov/court-of-appeals', 'D.C. Courts – Court of Appeals', '2026-05-13', 'static', 'official_source_direct', 'Judicial candidates and nominees', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('55ce9725fc53f713', 'DC', '["judicial"]', 'election_dates', 'What is the structure of the D.C. Superior Court?', '["D.C. trial court composition","How many judges on the D.C. Superior Court?","D.C. court of general jurisdiction"]', 'The D.C. Superior Court serves as the trial court of general jurisdiction. It is composed of 62 judges, appointed by the President to 15-year terms, who handle local civil, criminal, family, and probate matters.', 'https://www.dccourts.gov/superior-court/superior-court-judges', 'D.C. Courts – Superior Court', '2026-05-13', 'static', 'official_source_direct', 'Judicial candidates and nominees', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('d5bcd9228fae5398', 'DC', '["judicial"]', 'election_dates', 'What is the composition of the D.C. Judicial Nomination Commission (JNC)?', '["Who is on the JNC in D.C.?","Who picks the judges in Washington D.C.?","Judicial selection panel D.C."]', 'The JNC evaluates and recommends judicial nominees to the President. It consists of 7 members: two appointed by the Mayor, two by the D.C. Bar, one by the D.C. Council, one by the President, and one federal judge appointed by the Chief Judge of the U.S. District Court for D.C.', 'https://jnc.dc.gov/page/about-jnc', 'D.C. Judicial Nomination Commission', '2026-05-13', 'static', 'official_source_direct', 'Judicial candidates and legal counsel', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('e7d5da39aab9424f', 'DC', '["judicial"]', 'election_dates', 'How are the Chief Judges selected for the D.C. courts?', '["Are Chief Judges elected by their peers in D.C.?","D.C. Chief Judge term length","Selection of the D.C. Superior Court Chief Judge"]', 'Chief Judges are not elected by the other judges of the court. Under D.C. Code § 11-1503, they are specifically designated and appointed by the Judicial Nomination Commission (JNC) to serve four-year terms as Chief Judge, after which they may be reappointed.', 'https://jnc.dc.gov/page/judicial-service-district-columbia-courts-frequently-asked-questions', 'D.C. Code § 11-1503 / JNC FAQ', '2026-05-13', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('a037ed1984de3bd3', 'DC', '["municipal"]', 'election_dates', 'What is an Advisory Neighborhood Commission (ANC) in D.C.?', '["D.C. ANC role and structure","How many ANC seats are in Washington D.C.?","What does an ANC Commissioner do?"]', 'ANCs are hyper-local neighborhood advisory bodies in D.C. consisting of 296 unpaid Commissioners. Elected to two-year terms, ANC Commissioners advise the D.C. government on neighborhood issues such as zoning, liquor licenses, and public safety.', 'https://anc.dc.gov/page/about-ancs', 'D.C. Advisory Neighborhood Commissions', '2026-05-13', 'static', 'official_source_direct', 'Municipal candidates and strategists', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('a76875376a8d1345', 'DC', '["municipal"]', 'election_dates', 'What is a Single Member District (SMD) in D.C.?', '["ANC election districts D.C.","Smallest voting district in Washington D.C.","SMD definition D.C."]', 'A Single Member District (SMD) is the smallest unit of representative government in D.C. Each of the 296 ANC Commissioners is elected by and represents a specific SMD, which is drawn to include approximately 2,000 residents.', 'https://anc.dc.gov/page/about-ancs', 'D.C. Advisory Neighborhood Commissions', '2026-05-13', 'static', 'official_source_direct', 'Municipal candidates and strategists', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('e6e804539171ffb9', 'DC', '["state","municipal"]', 'voter_interaction', 'How much authority do Advisory Neighborhood Commissions (ANCs) have in D.C.?', '["ANC ''great weight'' statutory requirement","Does the D.C. government have to listen to the ANC?","Influence of ANC resolutions"]', 'While ANCs are advisory and cannot pass laws, D.C. Code legally requires that executive agencies, boards, and the D.C. Council give ''great weight'' to the formal recommendations of ANCs, requiring written justification if an agency decides to rule contrary to the ANC''s advice.', 'https://code.dccouncil.gov/us/dc/council/code/sections/1-309.10', 'D.C. Code § 1-309.10', '2026-05-13', 'static', 'statute_citation', 'Municipal candidates and D.C. agencies', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('8634785dade3a799', 'DC', '["state","municipal"]', 'voter_interaction', 'Are D.C. government employees restricted from participating in political campaigns?', '["D.C. Local Hatch Act","Can D.C. government workers volunteer for a campaign?","D.C. Code 1-612.02 political activity"]', 'Yes. Under the Local Hatch Act (D.C. Code § 1-612.02), D.C. government employees are permitted to engage in political campaigns, but they are strictly prohibited from using government time, resources, email, or their official authority to support or oppose candidates.', 'https://bega.dc.gov/page/local-hatch-act', 'D.C. Board of Ethics and Government Accountability (BEGA) – Hatch Act', '2026-05-13', 'static', 'official_source_direct', 'Campaigns and Volunteers', 'batch_2026-05-13T20-35-58_dc_full_v1'),
  ('c02273201741d193', 'DC', '["federal","state","municipal","judicial"]', 'voter_interaction', 'Are secure drop boxes available for mail-in ballots in Washington D.C.?', '["Can I put my absentee ballot in a drop box in D.C.?","Mail ballot drop boxes D.C.","How many drop boxes are in D.C.?"]', 'Yes. As part of its universal mail-in voting system, the D.C. Board of Elections deploys approximately 55 secure ballot drop boxes citywide, distributed across all 8 wards. They are open 24/7 until 8:00 p.m. on Election Day.', 'https://dcboe.org/Voters/Absentee-Voting/Mail-In-Voting', 'D.C. Board of Elections – Mail-In Voting', '2026-05-13', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-13T20-35-58_dc_full_v1')
